import React from 'react';
import Image from 'next/image';
import Link from 'next/link';

export default function FederationPage() {
    return (
        <main className="w-full bg-[#FAF6F0] overflow-hidden">
            {/* 1. Hero Section */}
            <section className="relative w-full pt-32 pb-24 px-6 md:px-12 lg:px-24 bg-[#2E5339] overflow-hidden">
                {/* Simulated Gold Veined Marble Overlay (Using subtle CSS gradient/pattern) */}
                <div className="absolute inset-0 opacity-20 pointer-events-none mix-blend-overlay" 
                     style={{
                         backgroundImage: 'url("data:image/svg+xml,%3Csvg width=\'100\' height=\'100\' viewBox=\'0 0 100 100\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M11 18c13.866 0 25.36 11.297 25.413 25.15 14.27 1.365 28.905 11.289 31.516 26.85-1.514-11.58-12.258-22.375-25.044-25.32C42.84 30.823 30.674 18.226 11 18zM60 49c14.115 0 26.046 11.046 27.282 25.101 10.963-3.618 17.584-18.069 11.196-33.805-4.48-11.03-16.736-22.847-28.84-29.215C56.634-1.229 42.112-2.316 28 2.053c15.823 4.542 28.534 16.63 32.554 32.533C61.464 36.632 62.43 42.508 60 49z\' fill=\'%23D4882E\' fill-opacity=\'0.8\' fill-rule=\'evenodd\'/%3E%3C/svg%3E")',
                         backgroundSize: '150px'
                     }}>
                </div>
                
                <div className="relative z-10 max-w-5xl mx-auto text-center">
                    <h1 className="text-4xl md:text-6xl font-extrabold text-white font-['Playfair_Display',serif] tracking-tight mb-4">
                        The Jammi Federation
                    </h1>
                    <p className="text-lg md:text-2xl text-[#D4882E] font-medium font-['DM_Sans',sans-serif] tracking-wide">
                        Uniting Ayurvedic Heritage with Global Scientific Excellence.
                    </p>
                </div>
            </section>

            {/* 2. Partnership Tiers (Zero Gaps) */}
            <section className="w-full flex flex-col md:flex-row">
                {/* Left: Scientific Research */}
                <div className="flex-1 bg-[#F0E8DC] p-10 md:p-14 border border-[#D4882E]/30 text-center flex flex-col items-center">
                    <div className="h-16 w-16 rounded-full bg-[#2E5339]/10 text-[#2E5339] flex items-center justify-center mb-6">
                        <span className="material-symbols-outlined text-[32px]">science</span>
                    </div>
                    <h3 className="text-2xl font-bold text-[#2E5339] font-['Playfair_Display',serif] mb-3">Scientific Research</h3>
                    <p className="text-slate-700 font-['DM_Sans',sans-serif] leading-relaxed">
                        Pioneering collaborations with IIT Delhi, ACTREC, and premium global laboratories to validate ancient formulations with modern metrics.
                    </p>
                </div>

                {/* Center: Clinical Alliances */}
                <div className="flex-1 bg-[#F0E8DC] p-10 md:p-14 border border-[#D4882E]/30 text-center flex flex-col items-center">
                    <div className="h-16 w-16 rounded-full bg-[#2E5339]/10 text-[#2E5339] flex items-center justify-center mb-6">
                        <span className="material-symbols-outlined text-[32px]">local_hospital</span>
                    </div>
                    <h3 className="text-2xl font-bold text-[#2E5339] font-['Playfair_Display',serif] mb-3">Clinical Alliances</h3>
                    <p className="text-slate-700 font-['DM_Sans',sans-serif] leading-relaxed">
                        Strategic partnerships with leading hospitals and governing medical bodies worldwide, ensuring safe, effective patient integration.
                    </p>
                </div>

                {/* Right: Supply Chain Integrity */}
                <div className="flex-1 bg-[#F0E8DC] p-10 md:p-14 border border-[#D4882E]/30 text-center flex flex-col items-center">
                    <div className="h-16 w-16 rounded-full bg-[#2E5339]/10 text-[#2E5339] flex items-center justify-center mb-6">
                        <span className="material-symbols-outlined text-[32px]">forest</span>
                    </div>
                    <h3 className="text-2xl font-bold text-[#2E5339] font-['Playfair_Display',serif] mb-3">Supply Chain Integrity</h3>
                    <p className="text-slate-700 font-['DM_Sans',sans-serif] leading-relaxed">
                        Exclusive wild sourcing partners empowering local farmers, ensuring unprecedented herb purity and strict ethical standards.
                    </p>
                </div>
            </section>

            {/* 3. Interactive Logo Wall */}
            <section className="w-full bg-white py-16 px-6 md:px-12 border-b border-[#D4882E]/20">
                <h2 className="text-center text-sm font-bold tracking-[0.2em] text-slate-500 uppercase mb-10">
                    Trusted By Elite Institutions
                </h2>
                <div className="max-w-7xl mx-auto flex flex-wrap justify-center items-center gap-12 md:gap-24">
                    {/* Placeholder logos that gain color on hover */}
                    <div className="grayscale hover:grayscale-0 opacity-60 hover:opacity-100 transition-all duration-500 cursor-pointer">
                        <h4 className="font-bold text-2xl text-[#2E5339]">IIT DELHI</h4>
                    </div>
                    <div className="grayscale hover:grayscale-0 opacity-60 hover:opacity-100 transition-all duration-500 cursor-pointer">
                        <h4 className="font-bold text-2xl text-[#0060A9]">TATA MEMORIAL</h4>
                    </div>
                    <div className="grayscale hover:grayscale-0 opacity-60 hover:opacity-100 transition-all duration-500 cursor-pointer">
                        <h4 className="font-bold text-2xl text-[#8E24AA]">UNIV OF MADRAS</h4>
                    </div>
                    <div className="grayscale hover:grayscale-0 opacity-60 hover:opacity-100 transition-all duration-500 cursor-pointer">
                        <h4 className="font-bold text-2xl text-[#D32F2F]">ACTREC</h4>
                    </div>
                </div>
            </section>

            {/* 4. Membership Benefits */}
            <section className="w-full bg-[#FAF6F0] py-16 px-6 md:px-12 flex justify-center">
                <div className="max-w-4xl w-full">
                    <h2 className="text-3xl md:text-4xl font-extrabold text-[#2E5339] font-['Playfair_Display',serif] mb-10 text-center">
                        Federation Membership Benefits
                    </h2>
                    <ul className="grid grid-cols-1 md:grid-cols-2 gap-6 md:gap-8">
                        {[
                            "Access to proprietary Ayurvedic clinical data and research archives.",
                            "Priority supply of standardized, Ayush-certified raw materials.",
                            "Joint participation in international clinical trials and publications.",
                            "Invitations to exclusive Jammi Federation global scientific summits.",
                            "Co-branding opportunities for rigorous clinical research projects.",
                            "Direct integration into the legacy Jammi supply chain ecosystem."
                        ].map((benefit, i) => (
                            <li key={i} className="flex items-start gap-4">
                                <span className="material-symbols-outlined text-[#D4882E] shrink-0 mt-0.5">eco</span>
                                <p className="text-slate-800 font-medium font-['DM_Sans',sans-serif] leading-snug">
                                    {benefit}
                                </p>
                            </li>
                        ))}
                    </ul>
                </div>
            </section>

            {/* 5. CTA */}
            <section className="w-full bg-[#D4882E] py-16 px-6 text-center shadow-inner">
                <div className="max-w-3xl mx-auto flex flex-col items-center">
                    <h2 className="text-3xl md:text-5xl font-black text-white font-['Playfair_Display',serif] mb-6">
                        Join the Federation
                    </h2>
                    <p className="text-white/90 text-lg mb-10 max-w-2xl leading-relaxed">
                        Become part of an elite ecosystem bridging rich ancient wisdom and rigorous modern science. We are actively seeking visionary partners.
                    </p>
                    <button className="bg-white text-[#D4882E] px-8 py-4 rounded-full font-bold uppercase tracking-widest text-sm shadow-xl hover:scale-105 hover:bg-[#2E5339] hover:text-white transition-all">
                        Download Prospectus
                    </button>
                </div>
            </section>
        </main>
    );
}
